mapper.update:
MERGE INTO MCP_AUTH_DATA
USING DUAL ON (ID = #{id})
	WHEN MATCHED THEN
		UPDATE SET
	        	 NAME = #{name}
	        	, TXID = #{txId}
             	, ACCESS_TOKEN = #{accessToken}
	        	, PLATFORM = #{platform}
	        	, SYS_RDATE = SYSDATE

	WHEN NOT MATCHED THEN
		INSERT (
             	  ID
             	, NAME
             	, TXID
             	, ACCESS_TOKEN
             	, PLATFORM
             	, SYS_RDATE
        )
		VALUES
		(
			 	  #{id}
			 	, #{name}
             	, #{txId}
             	, #{accessToken}
             	, #{platform}
             	, SYSDATE
      )
